#!/usr/bin/env node

/**
 * Test script to simulate rclnodejs not being available
 */

// Temporarily override require to simulate missing rclnodejs
const originalRequire = require;
require = function(id) {
  if (id === 'rclnodejs') {
    throw new Error('Cannot find module \'rclnodejs\'');
  }
  return originalRequire.apply(this, arguments);
};

// Test the check script
console.log('🧪 Testing with simulated missing rclnodejs...');
try {
  originalRequire('./check-rclnodejs.js');
} catch (error) {
  console.log('\n✅ Script correctly detected missing rclnodejs and exited with error');
  console.log('Exit code:', error.code || 'Error thrown');
}
